class Solution:
    def maximumLength(self, s: str) -> int:
        counts = defaultdict(int)
        if not s:
            return -1
        current_char = s[0]
        current_length = 1
        for i in range(1, len(s)):
            if s[i] == current_char:
                current_length += 1
            else:
                for l in range(1, current_length + 1):
                    key = (current_char, l)
                    counts[key] += (current_length - l + 1)
                current_char = s[i]
                current_length = 1
        for l in range(1, current_length + 1):
            key = (current_char, l)
            counts[key] += (current_length - l + 1)
        for l in range(len(s), 0, -1):
            for c in 'abcdefghijklmnopqrstuvwxyz':
                key = (c, l)
                if counts.get(key, 0) >= 3:
                    return l
        return -1
